local G = DYCLegendary local require = G.DYCModRequire local DYCMakeFX = require( "dyc_makefx" ) local dyc_fxlist = require( "dyc_fxlist" ) local DYCSpawnFX = function(name, pos, rot) for k, v in pairs(dyc_fxlist) do if name == v.name then local inst = DYCMakeFX(v, true) if pos then inst.Transform:SetPosition(pos:Get()) end if rot then inst.Transform:SetRotation(rot) end return inst end end end return DYCSpawnFX 